SELECT COUNT(DISTINCT f.user_id) AS feedback_engaged_users
FROM feedback AS f
JOIN user_engagement AS ue ON f.user_id = ue.user_id
WHERE f.feedback_score >= 3 AND ue.engagement_score = (
    SELECT MAX(engagement_score) FROM user_engagement
);

SELECT COUNT(DISTINCT f.user_id) 
FROM feedback f
JOIN notifications n ON f.user_id = n.user_id;

SELECT COUNT(utm_id) AS TotalUTMParameters
FROM utm_parameters
WHERE utm_source = 'Google' AND utm_medium = 'Email';

SELECT u.user_id, u.name
FROM users u
WHERE EXISTS (
    SELECT 1 FROM user_engagement ue
    WHERE u.user_id = ue.user_id AND ue.engagement_score > 0
) OR EXISTS (
    SELECT 1 FROM feedback f
    WHERE u.user_id = f.user_id AND f.feedback_score > 0
);

SELECT AVG(session_duration)
FROM user_sessions
WHERE session_id IN (
    SELECT DISTINCT session_id
    FROM page_views
);
